#!/usr/bin/env Rscript

# ==============================================================================
# Generate combined TCR/VDJ files and EBV CD8-only Seurat RDS
# ==============================================================================
#
# Purpose:
#   This script starts from the final combined Seurat object generated by
#   7_Merging_all_metadata.R. It:
#     1. scans Cell Ranger VDJ-T output folders,
#     2. combines filtered_contig_annotations.csv files across samples,
#     3. creates a stable VDJ barcode key for matching VDJ rows to Seurat cells,
#     4. optionally plots tetramer CLR distributions for multimer-positive cells,
#     5. applies tetramer-specific CLR cutoffs to remove weak/sticky staining,
#     6. subsets EBV CD8 samples while excluding CD4 batches,
#     7. exports combined and EBV-only VDJ CSV files, and
#     8. saves final filtered Seurat RDS objects.
#
# Expected input:
#   - Combined Seurat object from 7_Merging_all_metadata.R.
#   - Cell Ranger VDJ-T output directories containing:
#       filtered_contig_annotations.csv
#
# Notes:
#   - This script assumes the Seurat metadata contains an `id` column identifying
#     the original sample ID.
#   - The final Seurat cell names may have extra dataset prefixes from script 7.
#     Therefore, VDJ matching is done using `vdj_barcode_key`, not directly from
#     colnames(merged_obj).
#   - Tetramer calls are expected to already exist from earlier ADT processing.
#
# ==============================================================================


# ----------------------------- #
# 0. Load packages
# ----------------------------- #

suppressPackageStartupMessages({
  library(Seurat)
  library(dplyr)
