# ----------------------------- #
# 3. Helper functions
# ----------------------------- #

create_dir <- function(path) {
  dir.create(path, recursive = TRUE, showWarnings = FALSE)
}


create_parent_dir <- function(path) {
  dir.create(dirname(path), recursive = TRUE, showWarnings = FALSE)
}


escape_regex <- function(x) {
  gsub("([][{}()+*^$|\\\\?.])", "\\\\\\1", x)
}


load_combined_object <- function(input_rds) {
  
  if (!file.exists(input_rds)) {
    stop("Input RDS file does not exist: ", input_rds)
  }
  
  obj <- readRDS(input_rds)
  
  if (!inherits(obj, "Seurat")) {
    stop("Input RDS must contain a Seurat object.")
  }
  
  obj
}


apply_tetramer_replacements_vector <- function(x, replacements) {
  
  x <- as.character(x)
  
  if (is.null(replacements) || length(replacements) == 0) {
    return(x)
  }
  
  for (pattern in names(replacements)) {
    replacement <- replacements[[pattern]]
    
    x <- ifelse(
      !is.na(x) & grepl(pattern, x),
      sub(pattern, replacement, x),
      x
    )
  }
  
  x
}


ensure_sample_column <- function(obj, cfg) {
  
  meta <- obj@meta.data
  
  if (!cfg$id_col %in% colnames(meta)) {
    stop("Metadata does not contain required id column: ", cfg$id_col)
  }
  
  sample_missing <- !cfg$sample_col %in% colnames(meta) ||
    all(is.na(meta[[cfg$sample_col]]))
  
  if (!sample_missing) {
    return(obj)
  }
  
  if (!file.exists(cfg$sample_metadata_file)) {
    message(
      "Sample column is missing/empty, but sample metadata file was not found. ",
      "Using id as sample."
    )
    
    obj@meta.data[[cfg$sample_col]] <- obj@meta.data[[cfg$id_col]]
    return(obj)
  }
  
  message("Filling sample column from sample metadata file.")
  
  sample_df <- readxl::read_xlsx(
    path = cfg$sample_metadata_file,
    sheet = cfg$sample_metadata_sheet
  ) %>%
    as.data.frame()
  
  required_cols <- c(cfg$id_col, cfg$sample_col)
  
  if (!all(required_cols %in% colnames(sample_df))) {
    message(
      "Sample metadata file does not contain both id and sample columns. ",
      "Using id as sample."
    )
    
    obj@meta.data[[cfg$sample_col]] <- obj@meta.data[[cfg$id_col]]
    return(obj)
  }
  
  sample_map <- sample_df %>%
    select(all_of(required_cols)) %>%
    distinct(.data[[cfg$id_col]], .keep_all = TRUE)
  
  meta_joined <- meta %>%
    rownames_to_column("cell") %>%
    left_join(sample_map, by = cfg$id_col) %>%
    column_to_rownames("cell")
  
  obj@meta.data <- meta_joined
  
  obj
}


extract_raw_cell_barcode <- function(cell, sample_id) {
  
  cell <- as.character(cell)
  sample_id <- as.character(sample_id)
  
  if (is.na(sample_id) || !nzchar(sample_id)) {
    return(sub("^.*_", "", cell))
  }
  
  # This handles both:
  #   sample_barcode
  #   dataset_sample_barcode
  pattern <- paste0("^.*", escape_regex(sample_id), "_")
  raw <- sub(pattern, "", cell)
  
  raw
}


add_vdj_barcode_key <- function(obj, cfg) {
  
  meta <- obj@meta.data
  
  if (!cfg$id_col %in% colnames(meta)) {
    stop("Cannot create VDJ barcode key because id column is missing: ", cfg$id_col)
  }
  
  cells <- rownames(meta)
  sample_ids <- as.character(meta[[cfg$id_col]])
  
  raw_barcodes <- mapply(
    FUN = extract_raw_cell_barcode,
    cell = cells,
    sample_id = sample_ids,
    USE.NAMES = FALSE
  )
  
  valid_sample <- !is.na(sample_ids) & nzchar(sample_ids)
  
  vdj_keys <- ifelse(
    valid_sample,
    paste0(sample_ids, "_", raw_barcodes),
    NA_character_
  )
  
  obj@meta.data[[cfg$raw_cell_barcode_col]] <- raw_barcodes
  obj@meta.data[[cfg$vdj_barcode_key_col]] <- vdj_keys
  
  obj
}


extract_batch_from_path <- function(vdj_dir, base_dir) {
  
  vdj_dir <- normalizePath(vdj_dir, winslash = "/", mustWork = FALSE)
  base_dir <- normalizePath(base_dir, winslash = "/", mustWork = FALSE)
  base_dir <- sub("/+$", "", base_dir)
  
  rel <- sub(
    pattern = paste0("^", escape_regex(base_dir), "/?"),
    replacement = "",
    x = vdj_dir
  )
  
  batch <- strsplit(rel, "/", fixed = TRUE)[[1]][1]
  
  if (is.na(batch) || batch == "") {
    batch <- NA_character_
  }
  
  batch
}


find_vdj_dirs_for_source <- function(source_cfg) {
  
  base_dir <- source_cfg$base_dir
  patterns <- source_cfg$search_patterns
  
  search_paths <- file.path(base_dir, patterns)
  
  vdj_dirs <- unique(unlist(
    lapply(search_paths, Sys.glob),
    use.names = FALSE
  ))
  
  vdj_dirs <- vdj_dirs[dir.exists(vdj_dirs)]
  
  vdj_dirs
}


read_one_vdj_dir <- function(vdj_dir, source_cfg, sample_names, cfg) {
  
  sample_name <- basename(dirname(vdj_dir))
  
  if (!sample_name %in% sample_names) {
    return(NULL)
  }
  
  vdj_file <- file.path(vdj_dir, cfg$vdj_file)
  
  if (!file.exists(vdj_file)) {
    return(list(
      data = NULL,
      summary = tibble(
        source_id = source_cfg$source_id,
        sample = sample_name,
        batch = extract_batch_from_path(vdj_dir, source_cfg$base_dir),
        vdj_dir = vdj_dir,
        status = "missing_vdj_file",
        n_rows = NA_integer_,
        n_unique_vdj_barcodes = NA_integer_,
        error_message = paste("Missing file:", vdj_file)
      )
    ))
  }
  
  dat <- tryCatch(
    readr::read_csv(vdj_file, show_col_types = FALSE),
    error = function(e) e
  )
  
  if (inherits(dat, "error")) {
    return(list(
      data = NULL,
      summary = tibble(
        source_id = source_cfg$source_id,
        sample = sample_name,
        batch = extract_batch_from_path(vdj_dir, source_cfg$base_dir),
        vdj_dir = vdj_dir,
        status = "read_failed",
        n_rows = NA_integer_,
        n_unique_vdj_barcodes = NA_integer_,
        error_message = dat$message
      )
    ))
  }
  
  if (nrow(dat) == 0) {
    return(list(
      data = NULL,
      summary = tibble(
        source_id = source_cfg$source_id,
        sample = sample_name,
        batch = extract_batch_from_path(vdj_dir, source_cfg$base_dir),
        vdj_dir = vdj_dir,
        status = "empty_file",
        n_rows = 0L,
        n_unique_vdj_barcodes = 0L,
        error_message = NA_character_
      )
    ))
  }
  
  if (!cfg$vdj_barcode_col %in% colnames(dat)) {
    return(list(
      data = NULL,
      summary = tibble(
        source_id = source_cfg$source_id,
        sample = sample_name,
        batch = extract_batch_from_path(vdj_dir, source_cfg$base_dir),
        vdj_dir = vdj_dir,
        status = "missing_barcode_column",
        n_rows = nrow(dat),
        n_unique_vdj_barcodes = NA_integer_,
        error_message = paste("Missing barcode column:", cfg$vdj_barcode_col)
      )
    ))
  }
  
  batch <- extract_batch_from_path(vdj_dir, source_cfg$base_dir)
  raw_barcodes <- as.character(dat[[cfg$vdj_barcode_col]])
  
  dat <- dat %>%
    mutate(
      raw_barcode = raw_barcodes,
      barcode = paste0(sample_name, "_", raw_barcodes),
      id = sample_name,
      batch = batch,
      source_id = source_cfg$source_id,
      source_base = source_cfg$base_dir,
      vdj_dir = vdj_dir
    )
  
  list(
    data = dat,
    summary = tibble(
      source_id = source_cfg$source_id,
      sample = sample_name,
      batch = batch,
      vdj_dir = vdj_dir,
      status = "loaded",
      n_rows = nrow(dat),
      n_unique_vdj_barcodes = n_distinct(dat$barcode),
      error_message = NA_character_
    )
  )
}


scan_all_vdj_sources <- function(obj, cfg) {
  
  sample_names <- obj@meta.data[[cfg$id_col]] %>%
    as.character() %>%
    unique() %>%
    na.omit()
  
  vdj_entries <- list()
  scan_summaries <- list()
  
  message("Scanning VDJ sources for ", length(sample_names), " sample IDs.")
  
  counter <- 1
  
  for (source_cfg in cfg$vdj_sources) {
    
    message("Scanning source: ", source_cfg$source_id)
    
    vdj_dirs <- find_vdj_dirs_for_source(source_cfg)
    
    if (length(vdj_dirs) == 0) {
      scan_summaries[[counter]] <- tibble(
        source_id = source_cfg$source_id,
        sample = NA_character_,
        batch = NA_character_,
        vdj_dir = NA_character_,
        status = "no_vdj_dirs_found",
        n_rows = NA_integer_,
        n_unique_vdj_barcodes = NA_integer_,
        error_message = NA_character_
      )
      counter <- counter + 1
      next
    }
    
    for (vdj_dir in vdj_dirs) {
      
      result <- read_one_vdj_dir(
        vdj_dir = vdj_dir,
        source_cfg = source_cfg,
        sample_names = sample_names,
        cfg = cfg
      )
      
      if (is.null(result)) {
        next
      }
      
      scan_summaries[[counter]] <- result$summary
      
      if (!is.null(result$data)) {
        key <- paste(
          source_cfg$source_id,
          result$summary$sample,
          vdj_dir,
          sep = "||"
        )
        vdj_entries[[key]] <- result$data
      }
      
      counter <- counter + 1
    }
  }
  
  final_vdj <- if (length(vdj_entries) > 0) {
    bind_rows(vdj_entries)
  } else {
    tibble()
  }
  
  if (isTRUE(cfg$deduplicate_vdj_rows) && nrow(final_vdj) > 0) {
    
    dedup_cols <- intersect(
      c(
        "id", "barcode", "raw_barcode", "chain", "cdr3", "cdr3_nt",
        "v_gene", "d_gene", "j_gene", "c_gene", "productive",
        "full_length", "contig_id"
      ),
      colnames(final_vdj)
    )
    
    if (length(dedup_cols) > 0) {
      final_vdj <- final_vdj %>%
        distinct(across(all_of(dedup_cols)), .keep_all = TRUE)
    }
  }
  
  scan_summary <- if (length(scan_summaries) > 0) {
    bind_rows(scan_summaries)
  } else {
    tibble(
      source_id = character(),
      sample = character(),
      batch = character(),
      vdj_dir = character(),
      status = character(),
      n_rows = integer(),
      n_unique_vdj_barcodes = integer(),
      error_message = character()
    )
  }
  
  list(
    vdj = final_vdj,
    summary = scan_summary
  )
}


make_samples_without_vdj <- function(obj, final_vdj, cfg) {
  
  sample_ids <- obj@meta.data[[cfg$id_col]] %>%
    as.character() %>%
    unique() %>%
    na.omit()
  
  vdj_samples <- if (nrow(final_vdj) > 0 && "id" %in% colnames(final_vdj)) {
    unique(final_vdj$id)
  } else {
    character()
  }
  
  tibble(
    sample = setdiff(sample_ids, vdj_samples)
  )
}


plot_tetramer_clr_pages <- function(obj, cfg) {
  
  if (!isTRUE(cfg$make_tetramer_clr_plots)) {
    return(invisible(NULL))
  }
  
  required_cols <- c(cfg$tetramer_col, cfg$tetramer_clr_col)
  missing_cols <- setdiff(required_cols, colnames(obj@meta.data))
  
  if (length(missing_cols) > 0) {
    message(
      "Skipping tetramer CLR plots because required metadata columns are missing: ",
      paste(missing_cols, collapse = ", ")
    )
    return(invisible(NULL))
  }
  
  create_dir(cfg$output_plot_dir)
  
  plot_df <- obj@meta.data %>%
    rownames_to_column("cell") %>%
    as_tibble()
  
  if (!cfg$sample_col %in% colnames(plot_df)) {
    plot_df[[cfg$sample_col]] <- plot_df[[cfg$id_col]]
  }
  
  plot_df <- plot_df %>%
    mutate(
      !!cfg$tetramer_col := as.character(.data[[cfg$tetramer_col]]),
      !!cfg$tetramer_clr_col := as.numeric(.data[[cfg$tetramer_clr_col]])
    ) %>%
    filter(
      !is.na(.data[[cfg$tetramer_col]]),
      !is.na(.data[[cfg$tetramer_clr_col]]),
      !is.na(.data[[cfg$sample_col]])
    )
  
  if (
    isTRUE(cfg$plot_only_multimer_positive) &&
    cfg$multimer_col %in% colnames(plot_df)
  ) {
    plot_df <- plot_df %>%
      filter(.data[[cfg$multimer_col]] == cfg$multimer_positive_label)
  } else {
    plot_df <- plot_df %>%
      filter(.data[[cfg$tetramer_col]] != cfg$negative_tetramer_label)
  }
  
  plot_df <- plot_df %>%
    mutate(
      !!cfg$tetramer_col := apply_tetramer_replacements_vector(
        .data[[cfg$tetramer_col]],
        cfg$tetramer_replacements
      )
    ) %>%
    filter(.data[[cfg$tetramer_col]] %in% cfg$tetramer_order)
  
  present_tetramers <- cfg$tetramer_order[
    cfg$tetramer_order %in% unique(plot_df[[cfg$tetramer_col]])
  ]
  
  if (length(present_tetramers) == 0) {
    message("No tetramers available for plotting after filtering.")
    return(invisible(NULL))
  }
  
  tetramer_chunks <- split(
    present_tetramers,
    ceiling(seq_along(present_tetramers) / cfg$plot_tetramers_per_page)
  )
  
  for (i in seq_along(tetramer_chunks)) {
    
    tet_group <- tetramer_chunks[[i]]
    
    subset_df <- plot_df %>%
      filter(.data[[cfg$tetramer_col]] %in% tet_group) %>%
      mutate(
        !!cfg$tetramer_col := factor(.data[[cfg$tetramer_col]], levels = tet_group)
      )
    
    if (nrow(subset_df) == 0) {
      next
    }
    
    p <- ggplot(
      subset_df,
      aes(
        x = .data[[cfg$sample_col]],
        y = .data[[cfg$tetramer_clr_col]],
        fill = .data[[cfg$sample_col]]
      )
    ) +
      geom_violin(scale = "width", trim = FALSE) +
      geom_jitter(width = 0.2, size = 0.6, alpha = 0.6) +
      facet_wrap(as.formula(paste("~", cfg$tetramer_col)), scales = "free_y") +
      theme_minimal(base_size = 16) +
      labs(
        title = paste("Multimer-positive tetramer CLR expression - page", i),
        x = "Sample",
        y = "Tetramer CLR"
      ) +
      theme(
        axis.text.x = element_text(angle = 45, hjust = 1, size = 12),
        axis.text.y = element_text(size = 12),
        axis.title = element_text(size = 14, face = "bold"),
        strip.text = element_text(size = 14, face = "bold"),
        plot.title = element_text(size = 16, face = "bold", hjust = 0.5),
        legend.position = "none"
      )
    
    ggsave(
      filename = file.path(
        cfg$output_plot_dir,
        paste0("Multimer_positive_tetramer_CLR_page_", i, ".jpeg")
      ),
      plot = p,
      width = cfg$plot_width,
      height = cfg$plot_height,
      dpi = cfg$plot_dpi,
      limitsize = FALSE
    )
  }
  
  invisible(NULL)
}


apply_tetramer_cutoffs <- function(obj, cutoff_df, cfg) {
  
  required_cols <- c(cfg$tetramer_col, cfg$tetramer_clr_col)
  missing_cols <- setdiff(required_cols, colnames(obj@meta.data))
  
  if (length(missing_cols) > 0) {
    stop(
      "Cannot apply tetramer cutoffs because required columns are missing: ",
      paste(missing_cols, collapse = ", ")
    )
  }
  
  meta <- obj@meta.data %>%
    rownames_to_column("cell") %>%
    as_tibble() %>%
    mutate(
      !!cfg$tetramer_col := as.character(.data[[cfg$tetramer_col]]),
      !!cfg$tetramer_clr_col := as.numeric(.data[[cfg$tetramer_clr_col]])
    )
  
  if (!cfg$tetramer_raw_col %in% colnames(meta)) {
    meta[[cfg$tetramer_raw_col]] <- meta[[cfg$tetramer_col]]
  }
  
  meta[[cfg$tetramer_pre_cutoff_col]] <- apply_tetramer_replacements_vector(
    meta[[cfg$tetramer_col]],
    cfg$tetramer_replacements
  )
  
  meta[[cfg$tetramer_col]] <- meta[[cfg$tetramer_pre_cutoff_col]]
  
  cutoff_df <- cutoff_df %>%
    mutate(tetramer = as.character(tetramer))
  
  meta_cut <- meta %>%
    left_join(cutoff_df, by = setNames("tetramer", cfg$tetramer_col)) %>%
    rename(!!cfg$tetramer_cutoff_col := cutoff) %>%
    mutate(
      below_cutoff = !is.na(.data[[cfg$tetramer_cutoff_col]]) &
        !is.na(.data[[cfg$tetramer_clr_col]]) &
        .data[[cfg$tetramer_col]] != cfg$negative_tetramer_label &
        .data[[cfg$tetramer_clr_col]] < .data[[cfg$tetramer_cutoff_col]],
      
      !!cfg$tetramer_pass_cutoff_col := case_when(
        .data[[cfg$tetramer_col]] == cfg$negative_tetramer_label ~ FALSE,
        is.na(.data[[cfg$tetramer_cutoff_col]]) ~ NA,
        below_cutoff ~ FALSE,
        TRUE ~ TRUE
      ),
      
      !!cfg$tetramer_col := ifelse(
        below_cutoff,
        cfg$negative_tetramer_label,
        .data[[cfg$tetramer_col]]
      )
    ) %>%
    select(-below_cutoff) %>%
    column_to_rownames("cell") %>%
    as.data.frame()
  
  obj@meta.data <- meta_cut
  
  obj
}


make_cutoff_summary <- function(obj, cfg) {
  
  obj@meta.data %>%
    as_tibble() %>%
    mutate(
      tetramer_raw = as.character(.data[[cfg$tetramer_raw_col]]),
      tetramer_pre_cutoff = as.character(.data[[cfg$tetramer_pre_cutoff_col]]),
      tetramer_final = as.character(.data[[cfg$tetramer_col]]),
      tetramer_pass_cutoff = .data[[cfg$tetramer_pass_cutoff_col]]
    ) %>%
    count(
      tetramer_raw,
      tetramer_pre_cutoff,
      tetramer_final,
      tetramer_pass_cutoff,
      name = "n_cells"
    ) %>%
    arrange(tetramer_pre_cutoff, tetramer_final)
}


subset_ebv_cd8_object <- function(obj, cfg) {
  
  meta <- obj@meta.data %>%
    rownames_to_column("cell") %>%
    as_tibble()
  
  if (!cfg$batch_col %in% colnames(meta)) {
    stop("Cannot subset EBV samples because batch column is missing: ", cfg$batch_col)
  }
  
  if (!cfg$sample_col %in% colnames(meta)) {
    meta[[cfg$sample_col]] <- meta[[cfg$id_col]]
  }
  
  if (isTRUE(cfg$subset_ebv_by_sample)) {
    
    ebv_samples <- meta %>%
      filter(
        !is.na(.data[[cfg$batch_col]]),
        grepl(cfg$ebv_batch_regex, .data[[cfg$batch_col]])
      ) %>%
      pull(.data[[cfg$sample_col]]) %>%
      unique()
    
    cells_keep <- meta %>%
      filter(.data[[cfg$sample_col]] %in% ebv_samples) %>%
      pull(cell)
    
  } else {
    
    cells_keep <- meta %>%
      filter(
        !is.na(.data[[cfg$batch_col]]),
        grepl(cfg$ebv_batch_regex, .data[[cfg$batch_col]])
      ) %>%
      pull(cell)
  }
  
  ebv_obj <- subset(obj, cells = cells_keep)
  
  ebv_meta <- ebv_obj@meta.data %>%
    rownames_to_column("cell") %>%
    as_tibble()
  
  cells_keep_no_excluded <- ebv_meta %>%
    filter(
      is.na(.data[[cfg$batch_col]]) |
        !grepl(cfg$exclude_batch_regex, .data[[cfg$batch_col]], ignore.case = TRUE)
    ) %>%
    pull(cell)
  
  ebv_obj <- subset(ebv_obj, cells = cells_keep_no_excluded)
  
  ebv_obj
}


subset_vdj_to_seurat_cells <- function(vdj_df, obj, cfg) {
  
  if (nrow(vdj_df) == 0) {
    return(vdj_df)
  }
  
  if (!cfg$vdj_barcode_key_col %in% colnames(obj@meta.data)) {
    stop("Seurat object does not contain VDJ barcode key column: ", cfg$vdj_barcode_key_col)
  }
  
  keys_keep <- obj@meta.data[[cfg$vdj_barcode_key_col]] %>%
    as.character() %>%
    unique() %>%
    na.omit()
  
  vdj_df %>%
    filter(.data$barcode %in% keys_keep)
}


